/**
 * Tests for settings-override — M168 Phase 4 (#1914)
 *
 * Verifies the (sid, key) CRUD contract, isolation across sessions, and
 * that ON DELETE CASCADE removes overrides when the parent session goes
 * away (foreign key constraint enforced by openDb via foreign_keys=ON).
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { mkdtempSync, rmSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

import {
  deleteOverride,
  getOverride,
  listOverrides,
  setOverride,
} from '../../lib/settings-override.js';
import { __resetDbForTests, openDb } from '../../lib/session-registry.js';

function seedSession(sid: string): void {
  const db = openDb();
  const now = Math.floor(Date.now() / 1000);
  db.prepare(
    `INSERT INTO sessions (sid, pid, cwd, repo_hash, repo_path, started_at, last_heartbeat, status)
     VALUES (?, 1, '/x', 'h', '/x', ?, ?, 'running')`,
  ).run(sid, now, now);
  db.close();
  __resetDbForTests();
}

describe('lib/settings-override (#1914)', () => {
  let workDir: string;
  let prevEnv: string | undefined;

  beforeEach(() => {
    workDir = mkdtempSync(join(tmpdir(), 'ork-settings-override-'));
    const dbPath = join(workDir, 'sessions.db');
    prevEnv = process.env.ORK_SESSION_DB;
    process.env.ORK_SESSION_DB = dbPath;
    __resetDbForTests();
  });

  afterEach(() => {
    __resetDbForTests();
    if (prevEnv === undefined) delete process.env.ORK_SESSION_DB;
    else process.env.ORK_SESSION_DB = prevEnv;
    rmSync(workDir, { recursive: true, force: true });
  });

  it('setOverride + getOverride round-trip a value', () => {
    seedSession('s-a');
    setOverride('s-a', 'effort', 'high');
    expect(getOverride('s-a', 'effort')).toBe('high');
  });

  it('getOverride returns null for an unknown (sid, key) pair', () => {
    seedSession('s-a');
    expect(getOverride('s-a', 'missing')).toBeNull();
  });

  it('setOverride replaces an existing value (ON CONFLICT DO UPDATE)', () => {
    seedSession('s-a');
    setOverride('s-a', 'model', 'claude-opus');
    setOverride('s-a', 'model', 'claude-sonnet');
    expect(getOverride('s-a', 'model')).toBe('claude-sonnet');
  });

  it('listOverrides returns every row for the given sid, sorted by key', () => {
    seedSession('s-a');
    setOverride('s-a', 'model', 'claude-opus');
    setOverride('s-a', 'effort', 'high');
    setOverride('s-a', 'lang', 'en');

    const rows = listOverrides('s-a');
    expect(rows.map(r => r.key)).toEqual(['effort', 'lang', 'model']);
    expect(rows.map(r => r.value)).toEqual(['high', 'en', 'claude-opus']);
  });

  it('listOverrides returns [] when no rows match the sid', () => {
    seedSession('s-a');
    expect(listOverrides('s-a')).toEqual([]);
  });

  it('deleteOverride removes just that row', () => {
    seedSession('s-a');
    setOverride('s-a', 'effort', 'high');
    setOverride('s-a', 'model', 'claude-opus');
    deleteOverride('s-a', 'effort');

    expect(getOverride('s-a', 'effort')).toBeNull();
    expect(getOverride('s-a', 'model')).toBe('claude-opus');
  });

  it('deleteOverride is a no-op when the row is absent', () => {
    seedSession('s-a');
    expect(() => deleteOverride('s-a', 'never-set')).not.toThrow();
  });

  it('overrides are isolated per session — A does not leak to B', () => {
    seedSession('s-a');
    seedSession('s-b');
    setOverride('s-a', 'effort', 'high');
    setOverride('s-b', 'effort', 'low');

    expect(getOverride('s-a', 'effort')).toBe('high');
    expect(getOverride('s-b', 'effort')).toBe('low');

    // Deleting one session's override leaves the other intact.
    deleteOverride('s-a', 'effort');
    expect(getOverride('s-a', 'effort')).toBeNull();
    expect(getOverride('s-b', 'effort')).toBe('low');
  });

  it('FK ON DELETE CASCADE removes overrides when the session is deleted', () => {
    seedSession('s-cascade');
    setOverride('s-cascade', 'effort', 'high');
    expect(getOverride('s-cascade', 'effort')).toBe('high');

    // Delete the parent session row — overrides should cascade.
    const db = openDb();
    db.prepare('DELETE FROM sessions WHERE sid = ?').run('s-cascade');
    db.close();
    __resetDbForTests();

    expect(getOverride('s-cascade', 'effort')).toBeNull();
  });
});
